<?php

namespace App\Http\Controllers;

use GuzzleHttp\Client;
use App\Models\ServiceRequest; // Import the ServiceRequest model
use GuzzleHttp\Exception\RequestException;
use App\Mail\ServiceRequestAdminMail;
use App\Mail\ServiceRequestUserMail;
use Illuminate\Http\Request;
use Illuminate\View\View;

class HomeController extends Controller
{
    // Helper function to clean HTML for description_completa
    private function cleanHtmlDescription($html) {
        $html = preg_replace('/<a[^>]*>(.*?)<\/a>/is', '$1', $html); // Remove <a> tags but keep content
        $html = preg_replace('/style="[^"]*"/i', '', $html);        // Remove style attributes
        $allowed_tags = '<b><strong><em><i><u><ul><li><p><h4><br>';
        return strip_tags($html, $allowed_tags);
    }

    /**
     * Mostra la homepage pubblica dell'applicazione.
     */
    public function index(): View
    {
        // Per ora, questa funzione restituisce semplicemente la vista 'home'.
        // In futuro, potremmo passare dati a questa vista dal database.
        return view('home');
    }

    /**
     * Mostra la pagina di selezione dei servizi Cassa Edile / Edilcassa.
     */
    public function serviziIndex(): View
    {
        return view('servizi.index');
    }

    /**
     * Mostra l'elenco delle prestazioni della Cassa Edile.
     */
    public function cassaEdile(): View
    {
        // In futuro, questi dati verranno dal database.
        // Add 'service_type' to each service for tracking
        $prestazioniCassaEdile = [
            ['nome' => 'Pagamento GNF', 'icona' => 'bi-cash-stack', 'descrizione' => 'Erogazione del trattamento economico per ferie e gratifica natalizia.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile gestisce l’accantonamento degli importi versati dall’impresa per i propri dipendenti a titolo di <strong>Gratifica Natalizia</strong> e <strong>Ferie (GNF)</strong>, provvedendo alla liquidazione delle quote accantonate con due pagamenti semestrali:</p><ul><li style="list-style-type: none"><ul><li><p><strong>Trattamento economico per ferie</strong>: l’equivalente delle somme accantonate <strong>dal 1° ottobre al 31 marzo</strong> viene corrisposto nel corso del mese di luglio;</p></li><li><p><strong>Gratifica natalizia</strong>: l’equivalente delle somme accantonate <strong>dal 1° aprile al 30 settembre</strong> viene corrisposto nel corso del mese di dicembre.</p></li></ul></li></ul><p>Il pagamento della prestazione avviene in automatico sulla base degli accantonamenti mensili previsti a carico dell’impresa e del lavoratore (con riferimento a quanto calcolato in busta paga) e in riscontro dell’avvenuto versamento delle somme dovute effettuato dall’impresa.</p><p><strong>Note:</strong></p><p>Al fine di beneficiare della prestazione è necessario che il lavoratore iscritto fornisca alla Cassa Edile i dati bancari/postali e le coordinate IBAN per l’accredito tramite bonifico delle somme spettanti sul proprio conto corrente.</p><p>.</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Pagamento APE', 'icona' => 'bi-person-workspace', 'descrizione' => 'Un premio per l\'Anzianità Professionale Edile.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>Ogni anno la Cassa Edile liquida ai lavoratori iscritti <strong>in automatico</strong> e di regola nel mese di <strong>MAGGIO</strong> un Premio di professionalità disciplinato dal CCNL vigente collegato all’anzianità lavorativa che l’operaio matura nel settore edile.<br><br>Alla copertura degli oneri derivanti dalla disciplina contrattualmente disposta dell’<strong>Anzianità Professionale Edile (A.P.E.)</strong> si provvede con un contributo a carico dei datori di lavoro.<br><br>A seguito del versamento da parte delle imprese del contributo, calcolato sugli elementi della retribuzione per tutte le ore di lavoro effettivamente prestate e sul trattamento economico per le festività, all’operaio che in un biennio abbia maturato l’A.P.E., anche in più circoscrizioni territoriali, le Casse Edili corrispondono, nell’anno successivo – ciascuna per la propria competenza – la prestazione prevista.<br><br>Per aver diritto alla prestazione il lavoratore deve far valere nel biennio precedente all’erogazione almeno 2100 ore denunciate e versate presso la Cassa Edile di Roma o altre Casse. Ogni biennio scade il 30 settembre dell’anno precedente quello dell’erogazione.<br><br>La prestazione è stabilita secondo importi crescenti, in relazione al numero delle erogazioni del Premio A.P.E. percepite negli anni dal singolo operaio e calcolata moltiplicando i coefficienti prestabiliti per il numero di ore di lavoro ordinario effettivamente prestate, denunciate e versate alla Cassa Edile per il secondo anno del biennio (l’anno base per la liquidazione è il secondo del biennio).<br><br>Le erogazioni di importi a titolo di Anzianità Professionale Edile sono <strong>soggette a ritenuta IRPEF</strong> (la Cassa Edile emette pertanto la certificazione CU da considerare in fase di dichiarazione dei redditi).</p><br>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Regolamento APE – CCNL Allegato C Comma 4', 'icona' => 'bi-file-earmark-ruled', 'descrizione' => 'Cumulo delle ore di lavoro per operai che si trasferiscono.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>Nel caso di morte o di invalidità permanente assoluta al lavoro di operai che abbiano percepito almeno una volta la prestazione o comunque abbiano maturato il requisito per l’ottenimento dell’A.P.E. e per i quali nel biennio precedente l’evento siano stati effettuati gli accantonamenti relativi a Gratifica Natalizia e Ferie, la Cassa Edile, su richiesta dell’operaio o degli aventi causa (eredi), eroga una prestazione <strong>pari a 300 volte la retribuzione oraria minima contrattuale</strong> costituita dal minimo di paga base spettante all’operaio stesso al momento dell’evento.</p><br>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Indennità per Carenza Malattia', 'icona' => 'bi-bandaid', 'descrizione' => 'Indennità per i primi 3 giorni di malattia.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile corrisponde un’indennità giornaliera definita “per carenza”, fissata in <strong>€ 36,00</strong> per i primi tre giorni, a persona, nel singolo anno solare e per un solo evento di malattia di durata non superiore a 6 giorni di calendario (1° gennaio – 31 dicembre), entro un limite massimo di <strong>€ 108,00</strong>.<br><br>Per avere diritto alla prestazione il lavoratore <strong>alla data dell’evento sanitario</strong> deve essere in forza con un’impresa iscritta e regolare alla BNI (avendo effettuato denunce e versamenti dei contributi dovuti) ed aver accantonato, nel corso dei 24 mesi precedenti, un numero minimo di 2100 ore di lavoro ordinario.<br><br>Per l’attivazione della richiesta della prestazione, oltre alla domanda del lavoratore è necessario che l’impresa comunichi l’evento tramite Denuncia MUT, allegando contestualmente la certificazione medica attestante la durata della malattia.</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Borse di Studio', 'icona' => 'bi-mortarboard-fill', 'descrizione' => 'Assegnazione di borse di studio per i figli dei lavoratori.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile organizza annualmente per gli studenti figli dei lavoratori iscritti fiscalmente a carico e/o conviventi e i lavoratori studenti, che frequentino con profitto le scuole degli ordini e gradi indicati e che non risultino ripetenti o promossi con debito formativo né fuori corso e non aggiudicatari di altri premi analoghi nello stesso anno scolastico/accademico di afferenza, un concorso per l’assegnazione di una serie precisata di <strong>Borse di Studio</strong>.<br><br>Le modalità, il numero dei premi, i requisiti di partecipazione, i criteri di conferimento e la documentazione da presentare saranno resi noti nel Bando di Partecipazione, che sarà pubblicato sul sito della Cassa Edile orientativamente nel mese di <strong>GENNAIO</strong>.</p><br>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Assistenza allo Studio', 'icona' => 'bi-book-half', 'descrizione' => 'Contributo per l\'acquisto di libri di testo.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile riconosce ai lavoratori iscritti che abbiano figli frequentanti <strong>Scuole Secondarie di secondo grado</strong>, non fruitori di Borsa di Studio erogata dalla Cassa Edile di Roma per il precedente anno scolastico, un contributo economico “<strong>pro-capite</strong>” allo studio di <strong>€ 155,00</strong> (l’importo è soggetto a ritenuta IRPEF).<br><br>L’attivazione della richiesta della prestazione da parte del lavoratore può avvenire <strong>dal 1° Febbraio e fino al 30 Giugno</strong> anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.<br><br>Per avere diritto alla prestazione il lavoratore nel corso dei 12 mesi precedenti la data del <strong>1° febbraio</strong> di ogni anno scolastico deve aver accantonato un numero minimo di 950 ore di lavoro ordinario.<br><br>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Certificato di iscrizione e frequenza ai corsi di scuola secondaria di secondo grado;</p></li><li>Attestazione della Situazione di Famiglia;</li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data dell’evento <strong>(riferimento alla data del 1° novembre di ogni anno scolastico)</strong>;</p></li><li><p>Sottoscrizione del consenso al trattamento dei dati personali anche dei familiari.</p></li></ul></li></ul><br>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Premio Giovani', 'icona' => 'bi-award-fill', 'descrizione' => 'Premio per i giovani che entrano per la prima volta nel settore.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile di Roma riconosce&nbsp; ai giovani di età anagrafica compresa tra i <strong>15° e i 25° anni di età, dopo aver maturato per la prima volta </strong>la prestazione per Anzianità Professionale Edile presso la Cassa Edile di Roma, ma non aver mai percepito il premio per Anzianità Professionale Edile da altre province,&nbsp; <strong>per una sola volta</strong> <strong>un premio di €500,00</strong> (l’importo è soggetto a ritenuta IRPEF)</p><p>&nbsp;</p><p>L’attivazione della richiesta della prestazione da parte del lavoratore può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>&nbsp;</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data della presentazione della domanda, contenente oltre alla data di assunzione, i seguenti dati: cognome, nome, data di nascita, codice fiscale, qualifica e mansione;</p></li><li>Sottoscrizione del consenso al trattamento dei dati personali.</li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Fondo Prepensionamento', 'icona' => 'bi-hourglass-bottom', 'descrizione' => 'Incentivo all\'esodo per i lavoratori prossimi alla pensione.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>In via sperimentale, <b>dal 01/10/2023 al 31/12/2026</b> l’operaio iscritto alla Cassa Edile di Roma che abbia cessato il rapporto di lavoro con l’azienda, provata la sussistenza dei requisiti richiesti, potrà chiedere, <b>a titolo di accompagnamento al diritto alla pensione,</b> una delle prestazioni più avanti indicate.</p><p><b>Requisiti:</b><br><u>Requisito Lavoratore</u>: Essere un lavoratore dipendente titolare di un rapporto di lavoro subordinato in stato di disoccupazione per licenziamento o risoluzione consensuale che diano accesso alla <b>Nuova Assicurazione Sociale per l’Impiego (NASpI)</b>.<br><u>Requisito Cassa Edile</u>: Aver maturato almeno <b>2.100 ore</b> coperte da contribuzione valide ai fini APE nei 24 mesi precedenti la data di cessazione del rapporto di lavoro (sono valide anche le eventuali ore dichiarate in altre Casse Edili).</p><h2><strong>Procedimento</strong></h2><p><strong>Prima fase: fino a tutto il periodo di NASpI</strong><br>• Compilazione <b>DOMANDA</b> (Mod.1)</p><p><b>Documentazione da esibire:</b><br><em>Il lavoratore deve farsi assistere da un Patronato.</em><br>• Ecocert o specifica certificazione INPS per pensione anticipata;<br>• ipotesi data presunta di pensionamento;<br>• stima ipotetica della NASpI spettante;<br>• documento di liquidazione prestazione NASpI da parte dell’INPS.</p><p><b>Prestazione prevista</b> (l’opzione deve essere indicata espressamente dal lavoratore sul Mod.1):</p><p><b>Per il periodo di NASpI</b>, il lavoratore potrà fruire dell’<b>integrazione al 100%</b> dal mese di inizio della decurtazione – décalage in poi (bimestralmente), fino all’importo massimo mensile riconosciuto, previa presentazione di idonea documentazione attestante l’avvenuta liquidazione della prestazione da parte dell’INPS (copia bonifico) nel bimestre di riferimento.</p><p><strong>Seconda fase: terminato il periodo di NASpI</strong><br>• Compilazione AUTOCERTIFICAZIONE (Mod.4)</p><p>* L’apposita autocertificazione sul completo utilizzo di tutto il periodo di NASpI deve essere presentata prima dell’effettiva erogazione delle altre prestazioni.</p><p><b>Documentazione da esibire:</b><br><em>Il lavoratore deve farsi assistere da un Patronato.</em><br>• Modello C2, rilasciato dal Centro per l’Impiego (elenco storico dei rapporti di lavoro effettuati);<br>• <b>Trimestralmente, per documentare lo stato di disoccupazione</b>: Modello C2, rilasciato dal Centro per l’Impiego (elenco storico dei rapporti di lavoro effettuati) + autocertificazione sullo stato di disoccupazione (Mod.4);<br>• <u><b>Solo per la CONTRIBUZIONE VOLONTARIA</b></u>: <b>Autorizzazione dell’INPS</b>, in accoglimento della relativa domanda, alla prosecuzione della contribuzione volontaria; copia <b>bollettini INPS da pagare</b> (per conoscere l’importo da erogare); trimestralmente, copia del precedente <b>bollettino INPS pagato</b>.</p><p><strong>Prestazioni previste</strong> (sono quelle scelte e indicate espressamente dal lavoratore sul Mod.1):</p><p><b>Concluso il periodo di NASpI</b>, la Cassa Edile, in base alla scelta del lavoratore, provvederà a:</p><ul><li>nel caso di <b>INTEGRAZIONE AL REDDITO</b>, erogare il massimale medio netto mensile della Cassa Integrazione Guadagni ordinaria, in vigore alla data di presentazione della domanda (con riferimento agli importi dei trattamenti di integrazione salariale riportati nella relativa tabella INPS).</li></ul><p><b>Requisito anagrafico</b>: Per calcolare il raggiungimento dell’età minima per ottenere la pensione, vanno sommati gli anni dell’<b>età anagrafica</b> del lavoratore alla <b>fine del periodo della NASpI</b> più i <b>mesi di integrazione al reddito</b> (max 36).</p><ul><li>nel caso di <b>CONTRIBUZIONE VOLONTARIA</b>, pagare l’importo desunto dai bollettini trimestrali forniti dall’INPS al lavoratore (pagamento trimestrale anticipato).</li></ul><p><b>N.B.:</b> Tutte le prestazioni (Integrazione NASpI, Integrazione al reddito, Contribuzione volontaria) verranno assoggettate dalla Cassa Edile <b>a ritenuta fiscale</b>, calcolata sulle aliquote IRPEF a scaglioni. La Cassa Edile tratterrà la ritenuta e la verserà all’Agenzia delle Entrate. L’anno successivo emetterà la relativa CU, che il lavoratore dovrà esibire in sede di Dichiarazione dei redditi.</p><h4><em><strong><u>Modulistica</u></strong></em></h4><p>&nbsp;</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Pacchetti Vacanze e Soggiorni', 'icona' => 'bi-suitcase-lg-fill', 'descrizione' => 'Offerte di pacchetti vacanze a condizioni agevolate.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile, nell’ambito delle attività turistico-ricreative, organizza annualmente per i lavoratori iscritti e i loro familiari (coniuge/convivente e figli) fiscalmente a carico un concorso per la selezione ai <strong>Pacchetti Vacanze e Soggiorni</strong> previsti in luoghi di <strong>mare</strong> o <strong>montagna</strong> esclusivamente prescelti.</p><br><p>Le modalità, i requisiti di partecipazione, i criteri di selezione e la documentazione da presentare saranno resi noti nel Bando di Partecipazione, che sarà pubblicato sul sito della Cassa Edile orientativamente nel mese di <strong>MAGGIO</strong>.</p><br>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Fondi Pensione', 'icona' => 'bi-piggy-bank-fill', 'descrizione' => 'Supporto per l\'adesione ai fondi di pensione complementare.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile gestisce anche le pratiche di previdenza complementare del settore edile svolgendo una funzione di collegamento tra i lavoratori iscritti ed il <strong>Fondo Prevedi</strong> in rapporto a tre tipologie di servizi:</p><ul><li style="list-style-type: none"><ul><li>consegna e ritiro di documenti e modulistica;</li><li><p>registrazione e modifica dei dati personali dei lavoratori relativamente alla gestione del Fondo;</p></li><li><p>raccolta e trasferimento al Fondo di documenti e modulistica (es.: adesione, anticipazione, riscatto, ecc.).</p></li></ul></li></ul><p>La guida informativa e operativa del Fondo Prevedi è consultabile via web (https://www.prevedi.it/guida-al-fondo-pensione.php).</p><p>&nbsp;</p><p>Allo stesso tempo, provvede alla trasmissione al Fondapi (Fondo Nazionale Pensione complementare per i lavoratori delle piccole e medie imprese), la cui guida informativa e operativa è consultabile via web all’indirizzo https://www.fondapi.it, dei flussi contributivi corrispondenti alle preferenze di adesione esplicita o tacita dei lavoratori versati dalle imprese.</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Fondo SANEDIL', 'icona' => 'bi-heart-pulse-fill', 'descrizione' => 'Prestazioni sanitarie integrative per lavoratori e familiari.', 'descrizione_completa' => $this->cleanHtmlDescription('<p>La Cassa Edile svolge una funzione complementare e strumentale all’attivazione delle prestazioni e dei servizi previsti a favore dei lavoratori iscritti e dei familiari (coniuge/convivente e figli) fiscalmente a carico dal Fondo nazionale di assistenza sanitaria integrativa per i lavoratori dell’edilizia – SANEDIL, la cui descrizione è consultabile via web (https://www.fondosanedil.it/).</p><p>&nbsp;</p><p>L’iscrizione all’anzidetto Fondo, che costituisce la condizione necessaria per avere diritto e poter usufruire del corrispondente servizio di assistenza, avviene in automatico e si perfeziona con l’invio della prima denuncia che l’impresa effettua alla Cassa Edile per i lavoratori assunti come operai, ovvero anche al Fondo in caso i lavoratori siano impiegati.<br><br>L’entità dei costi e la descrizione delle singole prestazioni offerte ai lavoratori iscritti, e ove previsto ai loro familiari, è consultabile via web (https://www.fondosanedil.it/prestazioni-sanitarie/) nell’apposita guida al piano sanitario.<br><br>Le richieste di prestazioni sanitarie o rimborso, formulate tramite l’apposito modulo ricavabile via web (https://www.fondosanedil.it/istruzioni-operative/) e complete della documentazione prevista, possono essere fatte pervenire all’indirizzo mail dedicato: assistenzasanitaria@cassaedilediroma.it.</p><p>&nbsp;</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Indennizzo per la Donazione del Midollo Osseo', 'icona' => 'bi-droplet-half', 'descrizione' => 'Contributo economico per donazione di midollo osseo.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore dell’operaio iscritto una prestazione per la donazione del midollo osseo distinta in due ipotesi di importo forfettario:</p><ul><li style="list-style-type: none"><ul><li><strong>€ 52, 00</strong> per prelievo di sangue ai fini della Tipizzazione HLA;</li><li><p><strong>€ 129,00</strong> se, successivamente, viene richiesta la donazione di midollo osseo.</p></li></ul></li></ul><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data dell’evento</strong> (con riferimento al prelievo e/o alla donazione) deve essere in forza con un’impresa iscritta e regolare presso la BNI, ovvero abbia effettuato denunce e versamenti dovuti, ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li>Certificato del prelievo di sangue effettuato ai fini della Tipizzazione HLA;</li><li>Certificato del Centro sanitario attestante l’avvenuta donazione di midollo osseo;</li><li>Sottoscrizione del consenso al trattamento dei dati personali.</li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Indennizzo per la Donazione del Sangue', 'icona' => 'bi-droplet-fill', 'descrizione' => 'Contributo economico per ogni donazione di sangue.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore dell’operaio iscritto e dei familiari (coniuge/convivente e/o figli) fiscalmente a carico una prestazione per la donazione del sangue fissata in un importo forfettario di <strong>€ 26,00</strong>.</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data dell’evento</strong> (con riferimento al prelievo) deve essere in forza con un’impresa iscritta e regolare presso la BNI, ovvero abbia effettuato denunce e versamenti dovuti, ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Certificato del Centro trasfusionale dove è stato effettuato il prelievo di sangue con i relativi dati anagrafici ed il domicilio;</p></li><li><p>Sottoscrizione del consenso al trattamento dei dati personali anche dei familiari.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Assistenza per Alcolismo, HIV, Tossicodipendenza', 'icona' => 'bi-people-fill', 'descrizione' => 'Sostegno per lavoratori affetti da gravi patologie o dipendenze.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore del lavoratore iscritto e dei familiari (coniuge/convivente e figli) fiscalmente a carico nei casi di Alcolismo – HIV – Tossicodipendenza un rimborso spese per assistenza e cure presso Centri specializzati fino ad un importo massimo di <strong>€ 1.800,00</strong>.</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data della presentazione della domanda</strong> deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti, ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Certificato medico rilasciato dall’Azienda Sanitaria attestante la situazione clinica;</p></li><li><p>Certificato rilasciato dal Centro di recupero interessato attestante la terapia in atto;</p></li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data dell’evento (riferito alla data di emissione del certificato dell’Azienda Sanitaria);</p></li><li><p>Ricevute o fatture per le spese sostenute presso il Centro di recupero;</p></li><li>Attestazione della Situazione di Famiglia;</li><li><p>Sottoscrizione del consenso al trattamento dei dati personali anche dei familiari.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Supporti e protesi acustiche', 'icona' => 'bi-ear-fill', 'descrizione' => 'Contributo per l\'acquisto di apparecchi acustici.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore dei lavoratori iscritti e dei familiari (coniuge/convivente e figli) fiscalmente a carico un rimborso pari al <strong>50%</strong> delle spese sostenute nel biennio per un importo massimo erogabile di <strong>€ 1.800,00</strong> per nucleo familiare.</p><p>La data di inizio del biennio sarà determinata dalla data della <strong>prima autorizzazione</strong> da parte della Cassa Edile.</p><p>La richiesta della prestazione deve essere attivata<strong> entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data della presentazione della domanda</strong> deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti, ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li>Certificato medico rilasciato dall’Azienda Sanitaria;</li><li>Fattura originale descrittiva della spesa sostenuta;</li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data della presentazione della domanda;</p></li><li>Attestazione della Situazione di Famiglia;</li><li><p>Sottoscrizione del consenso al trattamento dei dati personali anche dei familiari.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Indennità per Malattia superiore al 180° giorno', 'icona' => 'bi-calendar-plus-fill', 'descrizione' => 'Indennità per malattia oltre i 180 giorni.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede un’indennità giornaliera di <strong>€ 21,00</strong> da corrispondere al lavoratore iscritto per gli eventi di malattia superiore al 180° giorno nel corso dello stesso anno solare (1 gennaio – 31 dicembre) in coincidenza con le giornate lavorative, fino al 365° giorno di calendario.</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data dell’evento sanitario</strong> deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti.</p><p>Per l’attivazione della richiesta della prestazione, oltre alla domanda del lavoratore è necessario che l’impresa comunichi l’evento tramite <strong>Denuncia MUT</strong>, allegando contestualmente la certificazione medica attestante la durata della malattia.</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Assistenza ai Familiari Portatori di Handicap', 'icona' => 'bi-person-wheelchair', 'descrizione' => 'Contributo per assistenza a familiari con handicap grave.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per l’anno di afferenza <strong>2025</strong>, prevede a favore dei lavoratori iscritti che abbiano un familiare (coniuge/convivente o figli) fiscalmente a carico riconosciuto portatore di handicap una prestazione economica annua distinta in due importi differenti in base al grado di inabilità:</p><ul><li style="list-style-type: none"><ul><li><p><strong>€ 1.300,00</strong> con riferimento alla <strong>Categoria B</strong>: sono incluse le situazioni di handicap che prevedono solo lo svolgimento delle funzioni vitali di base;</p></li><li><p><strong>€ 1.800,00</strong> con riferimento alla <strong>Categoria A</strong>: sono comprese le situazioni di handicap che rendono impossibile l’autonomo svolgimento delle funzioni vitali di base.</p></li></ul></li></ul><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data della presentazione della domanda</strong> deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti, ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Certificato medico rilasciato dall’Azienda Sanitaria attestante la diagnosi;</p></li><li>Verbale d’invalidità civile (meglio noto come “certificato d’invalidità”) o di handicap (indicato come “L.104/92”) specificante la diagnosi;</li><li><p>Certificato del Centro/Istituto di Riabilitazione interessato attestante la terapia in atto;</p></li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data della presentazione della domanda;</p></li><li>Attestazione della Situazione di Famiglia;</li><li><p>Sottoscrizione del consenso al trattamento dei dati personali anche dei familiari.</p></li></ul></li></ul><p><strong>N.B.</strong>: L’accoglimento della richiesta di prestazione è subordinato all’accertamento del medico fiduciario della Cassa Edile.</p>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Assegno Funerario per lavoratore e familiari', 'icona' => 'bi-flower1', 'descrizione' => 'Contributo per spese funerarie.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede in caso di decesso dei lavoratori iscritti, solo nei casi determinati da infortunio extraprofessionale o malattia extra professionale, e in qualunque modo dei familiari (coniuge/convivente o figli) fiscalmente a carico una prestazione economica fissata in un importo pari a <strong>€ 1.549,00</strong>, da erogarsi una sola volta.</p><p>Nel caso di decesso di un familiare fiscalmente a carico l’importo è <strong>soggetto a ritenuta IRPEF</strong>.</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p><span>Per avere diritto alla prestazione</span>:</p><ul><li><ul><li><p><strong>In caso di decesso del lavoratore</strong>: il lavoratore deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti, alla data dell’evento (data del decesso);</p></li><li><p><strong>In caso di decesso di un familiare fiscalmente a carico</strong>: il lavoratore deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti, alla data dell’evento (data del decesso) ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p></li></ul></li></ul><p>La <strong>documentazione necessaria</strong> è la seguente:</p><p style="padding-left: 40px"><strong>Punto A – decesso del lavoratore</strong></p><ul><li><ul><li>Copia della Denuncia di infortunio;</li><li>Copia della cartella clinica (in caso di ricovero);</li><li>Certificato anagrafico di morte;</li><li>Attestazione della Situazione di Famiglia;</li><li>Atto sostitutivo di notorietà;</li><li>Modulo di delega alla riscossione dei familiari (scaricabile dal sito);</li><li>Autorizzazione del giudice tutelare (nel caso di minori);</li><li>Atti penali (notizie sul fatto);</li><li>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data dell’evento (data del decesso);</li><li>Sottoscrizione del consenso al trattamento dei dati personali da parte dei familiari.</li></ul></li></ul><p style="padding-left: 40px"><strong>Punto B – decesso di un familiare</strong></p><ul><li><ul><li>Certificato anagrafico di morte;<br>Attestazione della Situazione di Famiglia;</li><li><p>Dichiarazione dell’Impresa attestante l’esistenza del rapporto lavoro alla data dell’evento (data del decesso);</p></li><li>Sottoscrizione del consenso al trattamento dei dati personali anche dei familiari.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Invalidità Totale da Malattia dei Familiari', 'icona' => 'bi-person-exclamation', 'descrizione' => 'Sussidio per invalidità totale di un familiare.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore del coniuge/convivente e dei figli fiscalmente a carico dei lavoratori iscritti una prestazione economica sui punti percentuali di invalidità per eventi morbosi provati da calcolarsi in rapporto al punteggio INAIL e con termini di calcolo differenti in base alle due tipologie di beneficiari:</p><ul><li style="list-style-type: none"><ul><li><p>Per il coniuge/convivente: <strong>€ 51,65</strong> X grado di invalidità non inferiore al 45%, fino ad un importo massimo di <strong>€ 5.165,00</strong>;</p></li><li><p>Per i figli: <strong>€ 36,15</strong> X grado di invalidità non inferiore al 45%, fino ad un importo massimo di <strong>€ 3.615,00</strong>.</p></li></ul></li></ul><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Per avere diritto alla prestazione il lavoratore <strong>alla data dell’evento sanitario</strong> deve essere in forza con un’impresa iscritta e regolare alla BNI, ovvero abbia effettuato denunce e versamenti dovuti, ed aver accantonato, nel corso dei 12 mesi precedenti, un numero minimo di 950 ore di lavoro ordinario.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Certificato medico rilasciato dall’Azienda Sanitaria attestante il decorso della malattia e la situazione clinica alla data della presentazione della domanda;</p></li><li><p>Certificato medico attestante la patologia in atto, alla data della presentazione della domanda, indicante un grado di inabilità superiore al 44%;</p></li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data della presentazione della domanda;</p></li><li>Attestazione della Situazione di Famiglia;</li><li><p>Sottoscrizione del consenso al trattamento dei dati personali da parte dei familiari.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Ricovero per Infortunio professionale', 'icona' => 'bi-hospital-fill', 'descrizione' => 'Indennità per ricovero da infortunio sul lavoro.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore dei lavoratori iscritti nel caso di ricovero a seguito di infortunio professionale l’erogazione di un’indennità giornaliera pari a <strong>€ 52,00</strong>, per un massimo di 90 giorni (escluso il giorno di dimissione) nell’arco dell’anno solare (1° gennaio – 31 dicembre).</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Il diritto alla prestazione è acquisito nel momento della presentazione della domanda.</p><p>Se in quel momento l’impresa non è in regola con il versamento di percentuali e contributi e il lavoratore risulti essere iscritto in base alla documentazione presente presso gli uffici della Cassa, avrà diritto a richiedere e ottenere per una sola volta la prestazione richiesta.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li><p>Copia della denuncia di infortunio presentata dall’impresa all’INAIL;</p></li><li>Copia della cartella clinica;</li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data dell’evento (con riferimento alla data dell’infortunio);</p></li><li><p>Sottoscrizione del consenso al trattamento dei dati personali.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Invalidità permanente per Infortunio professionale', 'icona' => 'bi-person-slash', 'descrizione' => 'Indennizzo per invalidità permanente da infortunio sul lavoro.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore dei lavoratori iscritti nel caso di infortunio professionale l’erogazione di una prestazione economica sui punti percentuali di invalidità fino ad un importo massimo di <strong>€ 35.800,00</strong>, da calcolarsi con riferimento al punteggio INAIL nel modo seguente: <strong>€ 360,00 </strong>per grado di invalidità, con l’applicazione di una franchigia assoluta prevista del 3% nei casi in cui il grado di invalidità sia inferiore al 12%.</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Il diritto alla prestazione è acquisito nel momento della presentazione della domanda.</p><p>Se in quel momento l’impresa non è in regola con il versamento di percentuali e contributi e il lavoratore risulti essere iscritto in base alla documentazione presente presso gli uffici della Cassa, avrà diritto a richiedere e ottenere per una sola volta la prestazione richiesta.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li style="list-style-type: none"><ul><li>Copia della denuncia di infortunio presentata dall’impresa all’INAIL;</li><li>Copia della cartella clinica (in caso di ricovero);</li><li>Fatture originali delle spese sostenute;</li><li><p>Copia Mod. INAIL 47-I, contenente l’esito della visita medica per accertamento dei postumi di inabilità permanente stabiliti in prima istanza;</p></li><li><p>Dichiarazione dell’impresa attestante l’esistenza del rapporto di lavoro alla data dell’evento (con riferimento alla data dell’infortunio);</p></li><li>Sottoscrizione del consenso al trattamento dei dati personali.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
            ['nome' => 'Decesso per Infortunio professionale', 'icona' => 'bi-person-x-fill', 'descrizione' => 'Indennizzo ai familiari per decesso da infortunio sul lavoro.', 'descrizione_completa' => $this->cleanHtmlDescription('<h4><span style="color: #f72525"><strong>* Trattasi di prestazione accordata di anno in anno in coincidenza delle disponibilità di bilancio.</strong></span></h4><p>La Cassa Edile, anche per gli eventi sanitari dal 1° ottobre 2024 al 30 settembre 2025, prevede a favore degli aventi causa (eredi) del lavoratore iscritto deceduto a seguito di infortunio professionale l’erogazione di una prestazione economica fissata in un importo forfettario pari a <strong>€ 39.800,00</strong>.</p><p>La richiesta della prestazione deve essere attivata <strong>entro il 31 dicembre 2025</strong>. L’attivazione può avvenire anche tramite l’indirizzo mail dedicato: prestazioni@cassaedilediroma.it.</p><p>Il diritto alla prestazione è acquisito nel momento della presentazione della domanda.</p><p>Se in quel momento l’impresa non è in regola con il versamento di percentuali e contributi e il lavoratore risulti essere iscritto in base alla documentazione presente presso gli uffici della Cassa, avrà diritto a ottenere la prestazione richiesta.</p><p>La <strong>documentazione necessaria</strong> è la seguente:</p><ul><li><ul><li>Copia della denuncia di infortunio presentata dall’impresa all’INAIL;</li><li>Copia della cartella clinica (in caso di ricovero);</li><li>Certificato anagrafico di morte;<br>Certificato medico di morte;</li><li>Attestazione della Situazione di Famiglia;</li><li>Atto sostitutivo di notorietà;</li><li>Modulo di delega alla riscossione dei familiari (scaricabile dal sito);</li><li>Autorizzazione del giudice tutelare (nel caso di minori);</li><li><p>Dichiarazione dell’Impresa attestante l’esistenza del rapporto di lavoro alla data dell’evento (data del decesso);</p></li><li>Dichiarazione dell’Autorità intervenuta;</li><li>Esame autoptico o copia dell’autopsia;</li><li><p>Atti penali (notizie sul fatto);<br>Sottoscrizione del consenso al trattamento dei dati personali da parte dei familiari.</p></li></ul></li></ul>'), 'service_type' => 'Cassa Edile'],
